#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    ll x,n;    cin >> x >> n;    ll cnt=n;    if(n%4==0){        cnt=0;     }    if(n%4==1){        cnt=-n;    }    if(n%4==2){        cnt=1;    }    if(n%4==3){        cnt=n+1;    }    if(x%2==0){        cout<<x+cnt<<"\n";    }    else{        cout<<x-cnt<<"\n";    }     } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}